import './Stepper.scss';

import { Icon } from ':components/Icon';
import { classNames } from ':helpers/classnames';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React from 'react';

import type { StepperProps } from './Stepper.types';

export const Stepper: FC<StepperProps> = ({ content, activeSlideIndex = 0, onPaginationChange }) => {
	const handleStep = (index: number) => () => {
		onPaginationChange?.(index);
	};

	return (
		<div className="dsb_onboarding_stepper">
			{content.map((_contentItem, index) => (
				<Icon
					key={index}
					size="small"
					iconName={Icons.Dot}
					onClick={handleStep(index)}
					className={classNames(
						'dsb_onboarding_stepper-step',
						index > 0 && 'dsb_onboarding_stepper-step__chained',
						index === activeSlideIndex && 'dsb_onboarding_stepper-step__active',
					)}
				/>
			))}
		</div>
	);
};
